/**
 * @module element/field/select
 * Provides styles for select dropdown input elements.
 */

import { color, spacing } from '@universityofmaryland/web-token-library';
import { create } from '../../utilities';
import type { JssObject } from '../../_types';
import { baseInput } from './_base';
import { valid, invalid } from './_state';

/**
 * Base64 encoded SVG for dark chevron down icon.
 * @private
 */

/**
 * Base64 encoded SVG for red chevron down icon.
 * @private
 */
const CHEVRON_DOWN_RED = `data:image/svg+xml;base64,`;

// Consistent naming
const classNamePrefix = 'umd-field-select';

/**
 * Base select dropdown styles.
 * @type {object}
 * @private
 */
export const select = {
  ...baseInput,

  "&[aria-invalid='true']": {
    ...invalid,
  },

  "&[aria-invalid='false']": {
    ...valid,
  },

  '&[multiple]': {
    cursor: 'pointer',
    resize: 'vertical',

    '& option': {
      padding: '5px',
      color: color.black,
      transition: 'color 0.3s',

      '&:hover': {
        color: color.red,
      },

      '&:checked': {
        backgroundColor: color.gray.light,
      },
    },
  },
};

/**
 * Select dropdown wrapper with custom dropdown indicator.
 * @returns {JssObject} Styles for select dropdown with chevron indicator.
 * @example
 * ```typescript
 * import * as Styles from '@universityofmaryland/web-styles-library';
 * Styles.element.field.select.selectWrapper
 * ```
 * @example
 * ```css
 * class="umd-field-select-wrapper"
 * ```
 * @example
 * ```text
 * Use 'umd-field-select-wrapper' instead of 'umd-forms-select-wrapper'.
 * ```
 * @since 1.1.0
 */
export const selectWrapper: JssObject = create.jss.objectWithClassName({
  backgroundColor: color.white,
  overflow: 'hidden',
  position: 'relative',

  className: [
    `${classNamePrefix}-wrapper`,
    /** @deprecated Use 'umd-field-select-wrapper' instead */
    'umd-forms-select-wrapper',
  ],

  '& select': {
    appearance: 'none',
    backgroundColor: 'transparent',
    cursor: 'pointer',
    paddingRight: spacing.lg,
    position: 'relative',
    zIndex: 9,
  },

  '&:before': {
    content: "''",
    backgroundImage: `url("${CHEVRON_DOWN_RED}")`,
    backgroundPosition: 'center center',
    backgroundSize: 'contain',
    backgroundRepeat: 'no-repeat',
    display: 'block',
    position: 'absolute',
    right: spacing.sm,
    top: `calc(50% - ${spacing.min})`,
    zIndex: 0,
    height: spacing.sm,
    width: spacing.sm,
  },
});
